if vim.o.background == 'dark' then
	for group, attrs in pairs(colors_dark) do
		vim.api.nvim_set_hl(0, group, attrs)
	end
	term_dark()
else
	for group, attrs in pairs(colors_light) do
		vim.api.nvim_set_hl(0, group, attrs)
	end
	term_light()
end
